def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    base_exp = np.e
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for a in range(7, 0, -1):
                for b in range(1, a + 4):
                    val = ((ratio - a) ** 6) / ((a + b) * 1.1 + 2)
                    trig = np.sin(ratio * b / (a + 0.5))
                    priority += val * trig * np.tanh(val / (b + 0.3))
            priority += np.exp(ratio - 7) ** 1.7 * np.cos(ratio * 1.3) * 1.4
            if bin_cap < item * 0.5:
                priority += np.log1p(item * bin_cap) * 6
        elif 4 < ratio <= 7:
            s = 0
            for m in range(1, int(np.ceil(ratio)) + 5):
                for n in range(1, m + 3):
                    term1 = ((ratio - m) ** 4) * np.cos(ratio * m) / (n + 0.7)
                    term2 = np.sin(ratio * n / (m + 1)) * np.exp(-n / (m + 1))
                    s += np.tanh(term1) * np.sinh(term2) * 1.5
            priority = s + 12 * np.log(ratio) - 3 * np.tanh(ratio - 4)
            if bin_cap > item * 3:
                priority -= np.sqrt(ratio) * 5
        elif 2 <= ratio <= 4:
            s1 = 0
            s2 = 0
            for r1 in range(1, 15):
                s1 += ((ratio - 2) ** r1) / (r1 * 2.1) * np.cos(r1 * ratio * 1.2)
            for r2 in range(1, 12):
                s2 += ((4 - ratio) ** r2) / (r2 ** 1.5 + 0.9) * np.sin(r2 * ratio)
            priority = s1 * np.tanh(3 * ratio) - np.log(ratio) * 7 + s2 * 0.8
            if bin_cap < item * 0.9:
                priority += np.sqrt(item / (bin_cap + 0.8)) * 3.5
            else:
                priority -= np.exp(-ratio) * 3
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 20):
                s += ((2 - ratio) ** n) / (n ** 2 + 1) * (np.sin(n * ratio * i) + np.cos(n * i))
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.7)) * 5
            else:
                penalty = np.cos(15 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.1)) * 1.9
            for m in range(1, 8):
                priority += np.sin(m * ratio * (i + 1)) * ((ratio - 1) ** m) / (m + 0.5)
        elif 0.5 <= ratio < 1:
            s = 0
            for p in range(1, 25):
                s += ((1 - ratio) ** p) / (p * 5) * np.cos(p * item * 1.1)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for q in range(1, 9):
                priority += ((1 - ratio) ** q) * np.sin(q * item * 1.4) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 20):
                s += ((0.5 - ratio) ** k) / (k * 3) * np.cos(k * ratio * 3)
            priority = s + 2 / (bin_cap + 4)
            if int(item * 1.5) % 5 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 2) * 4
            for u in range(1, 10):
                priority += ((0.5 - ratio) ** u) / (u * 8) * np.cos(item * u * 1.2)
        else:
            s = 0
            for t in range(1, 15):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.8) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 3) * 5
            for v in range(1, 12):
                priority += ((0.2 - ratio) ** v) / (v * 9) * np.cos(item * v * 1.0)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.45
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.45
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
